function fb(a, b) { if (a) { return a; } return b; }
var command = fb($.input.command, '');
var userContext = fb($.input.userContext, '');
var now = new Date();
var dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
var timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });

var prompt = 'You are a voice command processor and personal AI assistant. Parse the following natural language command and generate a structured action plan.\n\n';
prompt += 'CURRENT CONTEXT:\n';
prompt += '- Date: ' + dateStr + '\n';
prompt += '- Time: ' + timeStr + '\n';
if (userContext) prompt += '- User context: ' + userContext + '\n';
prompt += '\n';
prompt += 'VOICE COMMAND: "' + command + '"\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Break the command into discrete actionable steps\n';
prompt += '- Identify which apps/services would be needed\n';
prompt += '- Estimate time and complexity for each step\n';
prompt += '- Flag any ambiguities that need clarification\n';
prompt += '- Provide a quick verbal response summary\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "interpretation": "what the user is asking for in one sentence",\n';
prompt += '  "verbalResponse": "short spoken response (as if Siri were responding)",\n';
prompt += '  "actionPlan": [\n';
prompt += '    { "step": 1, "action": "what to do", "service": "app or service needed", "details": "specific details", "estimatedTime": "time estimate" }\n';
prompt += '  ],\n';
prompt += '  "servicesNeeded": ["Calendar", "Email"],\n';
prompt += '  "clarificationsNeeded": ["any unclear parts"],\n';
prompt += '  "priority": "high/medium/low",\n';
prompt += '  "canAutomate": true\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiProcess.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { interpretation: raw, verbalResponse: 'I processed your request.', actionPlan: [], servicesNeeded: [] }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var command = $.input.command;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':speaking_head_in_silhouette: Voice Command Processed', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Command:* "' + command + '"' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':speech_balloon: _' + (fb(fb(ai.verbalResponse, ai.interpretation), '')) + '_' } });
blocks.push({ type: 'divider' });

var plan = fb(ai.actionPlan, []);
if (plan.length > 0) {
  var planText = '*:clipboard: Action Plan*\n';
  plan.forEach(function(step) {
    planText += '*Step ' + step.step + ':* ' + step.action + '\n';
    planText += '  _Service:_ ' + (fb(step.service, 'N/A')) + '  |  _Time:_ ' + (fb(step.estimatedTime, 'N/A')) + '\n';
    if (step.details) planText += '  _Details:_ ' + step.details + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: planText } });
}

var autoLabel = 'No'; if (ai.canAutomate) { autoLabel = 'Yes'; }
var services = fb(ai.servicesNeeded, []);
if (services.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':gear: *Services:* ' + services.join(', ') + '  |  *Priority:* ' + (fb(ai.priority, 'medium')) + '  |  *Automatable:* ' + autoLabel }] });
}

var clarifications = fb(ai.clarificationsNeeded, []);
if (clarifications.length > 0) {
  var clarText = ':question: *Needs Clarification:*\n';
  clarifications.forEach(function(c) { clarText += '  - ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: clarText } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + One CLI' }] });

var fallback = 'Voice Command: ' + command;
return { blocks: blocks, fallback: fallback };
